from collections import OrderedDict
from typing import Any, Optional

class LRUCache:
    """Least Recently Used cache with O(1) get and put operations.

    Args:
        capacity: Maximum number of items the cache can hold.

    Raises:
        ValueError: If capacity is less than 1.
    """

    def __init__(self, capacity: int) -> None:
        if capacity < 1:
            raise ValueError('capacity must be >= 1')
        self.capacity = capacity
        self._cache: OrderedDict = OrderedDict()

    def get(self, key: Any) -> Optional[Any]:
        """Retrieve an item from the cache, marking it as recently used.

        Returns None if the key is not in the cache.
        """
        if key not in self._cache:
            return None
        self._cache.move_to_end(key)
        return self._cache[key]

    def put(self, key: Any, value: Any) -> None:
        """Add or update an item in the cache.

        If the cache is full, evicts the least recently used item.
        """
        if key in self._cache:
            self._cache.move_to_end(key)
            self._cache[key] = value
        else:
            if len(self._cache) >= self.capacity:
                self._cache.popitem(last=False)
            self._cache[key] = value

    def __len__(self) -> int:
        return len(self._cache)

    def __contains__(self, key: Any) -> bool:
        return key in self._cache

import time
import functools
from typing import Any, Callable, Type, Tuple, TypeVar, Optional

F = TypeVar('F', bound=Callable[..., Any])

def retry(
    max_attempts: int = 3,
    exceptions: Tuple[Type[Exception], ...] = (Exception,),
    backoff_base: float = 2.0,
    initial_delay: float = 1.0,
) -> Callable[[F], F]:
    """Retry a function on specified exceptions with exponential backoff.

    Args:
        max_attempts: Maximum number of attempts (including the first try).
        exceptions: Tuple of exception types to catch and retry on.
        backoff_base: Multiplier for each successive delay.
        initial_delay: Delay before the first retry in seconds.

    Usage:
        @retry(max_attempts=3, exceptions=(ConnectionError,))
        def fetch_data():
            ...
    """
    def decorator(func: F) -> F:
        @functools.wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            last_exc: Optional[Exception] = None
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    last_exc = exc
                    if attempt < max_attempts:
                        delay = initial_delay * (backoff_base ** (attempt - 1))
                        time.sleep(delay)
            raise last_exc  # type: ignore
        return wrapper  # type: ignore
    return decorator

import threading
from typing import TypeVar, Type, Any

T = TypeVar('T', bound='Singleton')

class Singleton:
    """Thread-safe singleton base class.

    Usage:
        class MyService(Singleton):
            def __init__(self) -> None:
                self.value = 42

        a = MyService()
        b = MyService()
        assert a is b
    """
    _instances: dict = {}
    _lock: threading.Lock = threading.Lock()

    def __new__(cls: Type[T]) -> T:
        if cls not in cls._instances:
            with cls._lock:
                if cls not in cls._instances:
                    instance = super().__new__(cls)
                    cls._instances[cls] = instance
        return cls._instances[cls]  # type: ignore

    @classmethod
    def reset(cls: Type['Singleton']) -> None:
        """Reset the singleton instance (useful for testing)."""
        with cls._lock:
            cls._instances.pop(cls, None)
